class LocalStorageRepository extends ChangeNotifier {
  LocalStorageRepository(this._storage);

  final LocalStorageManager _storage;

  AuthTokens? get authTokens => _storage.getAuthTokens();
  UserProfile? get userProfile => _storage.getUserProfile();
  AppConfiguration? get appConfiguration => _storage.getAppConfiguration();
  bool get isAuthenticated => _storage.isAuthenticated;

  Future<void> saveSession({
    required AuthTokens tokens,
    UserProfile? profile,
  }) async {
    await _storage.setAuthTokens(tokens);
    if (profile != null) {
      await _storage.saveUserProfile(profile);
    }
    notifyListeners();
  }

  Future<void> updateUserProfile(UserProfile profile) async {
    await _storage.saveUserProfile(profile);
    notifyListeners();
  }

  Future<void> updateAppConfiguration(AppConfiguration configuration) async {
    await _storage.saveAppConfiguration(configuration);
    notifyListeners();
  }

  Future<void> logout({bool clearOfflineCache = false}) async {
    await _storage.clearUserSession();
    if (clearOfflineCache) {
      await _storage.clearAllCachedContent();
      await _storage.clearAllOfflineData();
    }
    notifyListeners();
  }
}